#include <stdio.h>
#include <string.h>

#define N 1000000

int f[N + 1];

int main() {
    int T, L, R, i, sum;

    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &L, &R);
        memset(f, 0, sizeof(f));
        for (i = 1; i <= R; i++)
            f[i] = (i & 1 ? R - i + 1 : i - 1);
        sum = 0;
        for (i = L; i <= R; i++)
            sum ^= f[i];
        printf("%d\n", sum);
    }
    return 0;
}

